using System.Collections;
using UnityEngine;

// Ataques que disparam projécteis ou criam outros objectos (Etapa 2.1).
// Usam EnemyAttackController.SpawnProjectile + ProjectileData/ProjectileController
// (Etapa 2.2): cada ataque calcula a velocidade inicial (direcção/arco) e o
// resto da configuração — velocidade-base, dano, leque, rajada, tracking,
// explosão, interacções, carregamento e sons — vem do asset ProjectileData.

/// <summary>Projéctil recto: dispara em linha recta na direcção do alvo, à velocidade de "projectileData".</summary>
[System.Serializable]
public class Attack_ProjectileStraight : EnemyAttack
{
    [Header("Projéctil Recto")]
    [Tooltip("Configuração do projéctil (Etapa 2.2). Velocidade, dano, leque, rajada, sons, etc.")]
    public ProjectileData projectileData;

    public Vector2 spawnOffset = Vector2.zero;

    public Attack_ProjectileStraight()
    {
        attackName = "Projéctil Recto";
        range = 8f;
        requiresLineOfSight = true;
        prepTime = 0.3f;
        recoveryTime = 0.4f;
        cooldown = 1.5f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        if (projectileData == null) yield break;

        Vector2 velocity = ctx.DirectionToTarget() * projectileData.speed;
        yield return ctx.SpawnProjectile(projectileData, spawnOffset, velocity);
    }
}

/// <summary>Projéctil em arco: lançado com uma trajectória parabólica (gravidade — "projectileData.gravityScale" deve ser > 0) que tenta atingir a posição actual do alvo.</summary>
[System.Serializable]
public class Attack_ProjectileArc : EnemyAttack
{
    [Header("Projéctil em Arco")]
    [Tooltip("Configuração do projéctil (Etapa 2.2). 'gravityScale' deve ser > 0 para descrever o arco.")]
    public ProjectileData projectileData;

    [Tooltip("Altura aproximada do arco (m).")]
    public float arcHeight = 3f;

    [Tooltip("Tempo de voo aproximado até à posição actual do alvo (s).")]
    public float flightTime = 0.8f;

    public Vector2 spawnOffset = Vector2.zero;

    public Attack_ProjectileArc()
    {
        attackName = "Projéctil em Arco";
        range = 8f;
        prepTime = 0.4f;
        recoveryTime = 0.4f;
        cooldown = 2f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        if (projectileData == null || ctx.Target == null) yield break;

        Vector2 from = (Vector2)ctx.transform.position + spawnOffset;
        Vector2 to = ctx.Target.position;
        Vector2 displacement = to - from;

        float g = Mathf.Abs(Physics2D.gravity.y) * Mathf.Max(0.01f, projectileData.gravityScale);
        float vy = Mathf.Sqrt(2f * g * Mathf.Max(0.01f, arcHeight));
        float vx = displacement.x / Mathf.Max(0.01f, flightTime);

        yield return ctx.SpawnProjectile(projectileData, spawnOffset, new Vector2(vx, vy));
    }
}

/// <summary>Projéctil teleguiado leve: persegue o alvo com uma curva suave, conforme "projectileData.tracksPlayer"/"trackingIntensity".</summary>
[System.Serializable]
public class Attack_ProjectileHoming : EnemyAttack
{
    [Header("Projéctil Teleguiado")]
    [Tooltip("Configuração do projéctil (Etapa 2.2). 'tracksPlayer' deve estar activo, 'trackingIntensity' baixo = curvas 'leves'.")]
    public ProjectileData projectileData;

    public Vector2 spawnOffset = Vector2.zero;

    public Attack_ProjectileHoming()
    {
        attackName = "Projéctil Teleguiado";
        range = 8f;
        requiresLineOfSight = true;
        prepTime = 0.4f;
        recoveryTime = 0.5f;
        cooldown = 2.5f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        if (projectileData == null) yield break;

        Vector2 velocity = ctx.DirectionToTarget() * projectileData.speed;
        yield return ctx.SpawnProjectile(projectileData, spawnOffset, velocity);
    }
}

/// <summary>Explosão em área: dano em área centrado no inimigo (ou num deslocamento), após o telegraph (prepTime).</summary>
[System.Serializable]
public class Attack_AreaExplosion : EnemyAttack
{
    [Header("Explosão")]
    public float explosionRadius = 2f;
    public Vector2 explosionOffset = Vector2.zero;

    public Attack_AreaExplosion()
    {
        attackName = "Explosão";
        range = 4f;
        prepTime = 0.6f;
        recoveryTime = 0.4f;
        cooldown = 3f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        Vector2 center = (Vector2)ctx.transform.position + explosionOffset;

        if (ctx.IsTargetWithin(center, explosionRadius))
        {
            Vector2 away = ctx.Target != null ? (Vector2)ctx.Target.position - center : Vector2.zero;
            ctx.DamagePlayer(damage, knockbackForce, away);
        }

        yield break;
    }
}

/// <summary>Cria outro inimigo ou projéctil (ex: "Bullet Bill"): instancia "enemyPrefab" (outro EnemyController) OU dispara "projectileData" via ProjectileController, lançado na direcção do alvo.</summary>
[System.Serializable]
public class Attack_SpawnEnemyOrProjectile : EnemyAttack
{
    [Header("Opção A — Criar Outro Inimigo")]
    [Tooltip("Prefab de outro inimigo (com EnemyController) a instanciar e lançar na direcção do alvo. Tem prioridade sobre 'projectileData'.")]
    public GameObject enemyPrefab;

    [Header("Opção B — Disparar Projéctil (Etapa 2.2)")]
    [Tooltip("Usado se 'enemyPrefab' estiver vazio: configuração do projéctil (ProjectileData) auto-propulsionado na direcção do alvo, à velocidade 'projectileData.speed'.")]
    public ProjectileData projectileData;

    public Vector2 spawnOffset = Vector2.zero;

    [Tooltip("Velocidade de lançamento de 'enemyPrefab' na direcção do alvo. Para 'projectileData', usa-se 'projectileData.speed'.")]
    public float launchSpeed = 5f;

    public Attack_SpawnEnemyOrProjectile()
    {
        attackName = "Criar Inimigo/Projéctil";
        range = 10f;
        prepTime = 0.4f;
        recoveryTime = 0.6f;
        cooldown = 4f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        if (enemyPrefab != null)
        {
            Vector3 pos = ctx.transform.position + (Vector3)spawnOffset;
            var go = Object.Instantiate(enemyPrefab, pos, Quaternion.identity);

            var rb = go.GetComponent<Rigidbody2D>();
            if (rb != null) rb.velocity = ctx.DirectionToTarget() * launchSpeed;

            yield break;
        }

        if (projectileData != null)
        {
            Vector2 velocity = ctx.DirectionToTarget() * projectileData.speed;
            yield return ctx.SpawnProjectile(projectileData, spawnOffset, velocity);
        }
    }
}
